import OpenAI from "openai";

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY || "sk-placeholder-key-set-in-env",
});

interface ChatRequest {
  message: string;
  conversationId?: string;
  tenantId?: string;
  agentId?: string;
  context?: string[];
}

interface ChatResponse {
  content: string;
  usage: { promptTokens: number; completionTokens: number; totalTokens: number };
  intent?: string;
  sentiment?: string;
}

export class ChatService {
  private defaultModel = process.env.OPENAI_MODEL || "gpt-4o";

  /**
   * Generate AI response for a message
   */
  async generateResponse(request: ChatRequest): Promise<ChatResponse> {
    const systemPrompt = this.buildSystemPrompt(request);
    const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [
      { role: "system", content: systemPrompt },
    ];

    // Add context if available
    if (request.context?.length) {
      messages.push({
        role: "system",
        content: `Relevant context:\n${request.context.join("\n")}`,
      });
    }

    messages.push({ role: "user", content: request.message });

    const completion = await openai.chat.completions.create({
      model: this.defaultModel,
      messages,
      temperature: 0.7,
      max_tokens: 1000,
    });

    const content = completion.choices[0]?.message?.content || "";

    return {
      content,
      usage: {
        promptTokens: completion.usage?.prompt_tokens || 0,
        completionTokens: completion.usage?.completion_tokens || 0,
        totalTokens: completion.usage?.total_tokens || 0,
      },
    };
  }

  /**
   * Generate streaming response
   */
  async generateStreamResponse(request: ChatRequest): Promise<ReadableStream> {
    const systemPrompt = this.buildSystemPrompt(request);

    const stream = await openai.chat.completions.create({
      model: this.defaultModel,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: request.message },
      ],
      temperature: 0.7,
      stream: true,
    });

    const encoder = new TextEncoder();

    return new ReadableStream({
      async start(controller) {
        for await (const chunk of stream) {
          const content = chunk.choices[0]?.delta?.content || "";
          if (content) {
            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ content })}\n\n`));
          }
        }
        controller.enqueue(encoder.encode("data: [DONE]\n\n"));
        controller.close();
      },
    });
  }

  /**
   * Summarize text
   */
  async summarize(text: string, maxLength?: number): Promise<string> {
    const completion = await openai.chat.completions.create({
      model: "gpt-4o-mini",
      messages: [
        {
          role: "system",
          content: `Summarize the following text concisely${maxLength ? ` in ${maxLength} words or less` : ""}.`,
        },
        { role: "user", content: text },
      ],
      temperature: 0.3,
    });

    return completion.choices[0]?.message?.content || "";
  }

  /**
   * Analyze sentiment
   */
  async analyzeSentiment(text: string) {
    const completion = await openai.chat.completions.create({
      model: "gpt-4o-mini",
      messages: [
        {
          role: "system",
          content:
            'Analyze the sentiment of the text. Return JSON: {"sentiment": "positive|negative|neutral", "score": 0-1, "emotions": ["emotion1"]}',
        },
        { role: "user", content: text },
      ],
      temperature: 0,
      response_format: { type: "json_object" },
    });

    return JSON.parse(completion.choices[0]?.message?.content || "{}");
  }

  /**
   * Translate text
   */
  async translate(text: string, targetLanguage: string): Promise<string> {
    const completion = await openai.chat.completions.create({
      model: "gpt-4o-mini",
      messages: [
        {
          role: "system",
          content: `Translate the following text to ${targetLanguage}. Only return the translation.`,
        },
        { role: "user", content: text },
      ],
      temperature: 0.3,
    });

    return completion.choices[0]?.message?.content || "";
  }

  private buildSystemPrompt(request: ChatRequest): string {
    return `You are Audira AI, a helpful WhatsApp customer support assistant.
You are professional, friendly, and concise.
Always respond in the same language as the user's message.
If you don't know the answer, say so honestly and offer to connect with a human agent.

Conversation ID: ${request.conversationId || "unknown"}
Tenant: ${request.tenantId || "unknown"}`;
  }
}

