        return { sent: true, timestamp: Date.now() };
      },
      {
        connection: { host: "localhost", port: 6379 },
        concurrency: 5,
        limiter: { max: 30, duration: 1000 }, // 30 messages per second
      }
    );

    worker.on("completed", (job) => {
      console.log(`[Queue] Message ${job.id} sent successfully`);
    });

    worker.on("failed", (job, err) => {
      console.error(`[Queue] Message ${job?.id} failed:`, err.message);
