### 2. Service Layer Pattern

#### Service Architecture

```typescript
// apps/api/src/modules/contacts/service.ts

import { prisma } from "@audira/database";
import { logger } from "../../lib/logger";
import { ContactValidator } from "./validator";

export class ContactService {
  private validator = new ContactValidator();

  async getContacts(
    tenantId: string,
    filters: GetContactsInput
  ): Promise<Contact[]> {
    logger.info("Fetching contacts", { tenantId, filters });

    try {
      const contacts = await prisma.contact.findMany({
        where: {
          tenantId,
          ...(filters.search && {
            OR: [
              { name: { contains: filters.search, mode: "insensitive" } },
              { phone: { contains: filters.search } },
              { email: { contains: filters.search, mode: "insensitive" } },
            ],
          }),
          ...(filters.tags && { tags: { hasSome: filters.tags } }),
          ...(filters.status && { status: filters.status }),
        },
        skip: (filters.page - 1) * filters.limit,
        take: filters.limit,
        orderBy: { createdAt: "desc" },
      });

      logger.info("Contacts fetched", { tenantId, count: contacts.length });
      return contacts;
    } catch (error) {
      logger.error("Error fetching contacts", { tenantId, error });
      throw new ServiceError("Failed to fetch contacts", 500);
    }
  }

  async createContact(
    tenantId: string,
    input: CreateContactInput
  ): Promise<Contact> {
    logger.info("Creating contact", { tenantId, input });

    // Validate input
    const validated = this.validator.validateCreate(input);

    // Check for duplicates
    const existing = await prisma.contact.findUnique({
      where: { tenantId_phone: { tenantId, phone: validated.phone } },
    });

    if (existing) {
      throw new ServiceError("Contact with this phone already exists", 409);
    }

    try {
      const contact = await prisma.contact.create({
        data: {
          tenantId,
          ...validated,
        },
      });

      // Emit event for other services
      await this.emitEvent("contact.created", { contact, tenantId });

      logger.info("Contact created", { tenantId, contactId: contact.id });
      return contact;
    } catch (error) {
      logger.error("Error creating contact", { tenantId, error });
      throw new ServiceError("Failed to create contact", 500);
    }
  }

  async updateContact(
    tenantId: string,
    contactId: string,
    input: UpdateContactInput
  ): Promise<Contact> {
    logger.info("Updating contact", { tenantId, contactId, input });

    // Verify ownership
    const contact = await prisma.contact.findUnique({
      where: { id: contactId },
    });

    if (!contact || contact.tenantId !== tenantId) {
      throw new ServiceError("Contact not found", 404);
    }

    const validated = this.validator.validateUpdate(input);

    try {
      const updated = await prisma.contact.update({
        where: { id: contactId },
        data: validated,
      });

      await this.emitEvent("contact.updated", { contact: updated, tenantId });

      logger.info("Contact updated", { tenantId, contactId });
      return updated;
    } catch (error) {
      logger.error("Error updating contact", { tenantId, contactId, error });
      throw new ServiceError("Failed to update contact", 500);
    }
  }

  private async emitEvent(event: string, data: any) {
    // Emit to event bus (Redis Pub/Sub or message queue)
    await redis.publish(`events:${event}`, JSON.stringify(data));
  }
}
```

