## рҹ’¬ Communication Patterns

### 1. Request-Response (REST)

```typescript
// Synchronous, blocking
app.post("/contacts", async (c) => {
  const contact = await contactService.createContact(data);
  return c.json(contact, 201);
});

// Use for: CRUD operations, immediate responses
```

### 2. Pub-Sub (Event-Driven)

```typescript
// Asynchronous, non-blocking
class ContactService {
  async createContact(data: CreateContactInput) {
    const contact = await prisma.contact.create({ data });

    // Emit event
    await redis.publish("events:contact.created", JSON.stringify({
      contactId: contact.id,
      tenantId: contact.tenantId,
      timestamp: new Date(),
    }));

    return contact;
  }
}

// Subscribe to events
redis.subscribe("events:contact.created", (message) => {
  const event = JSON.parse(message);
  // Handle event: update analytics, trigger workflows, etc.
});

