## рҹӣЎпёҸ Resilience & Fault Tolerance

### 1. Retry Logic

```typescript
// Exponential backoff retry
async function retryWithBackoff<T>(
  fn: () => Promise<T>,
  maxAttempts = 3,
  baseDelay = 1000
): Promise<T> {
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      return await fn();
    } catch (error) {
      if (attempt === maxAttempts) throw error;

      const delay = baseDelay * Math.pow(2, attempt - 1);
      await new Promise(resolve => setTimeout(resolve, delay));
    }
  }
}

// Usage
const contact = await retryWithBackoff(
  () => prisma.contact.findUnique({ where: { id } }),
  3,
  1000
);
```

### 2. Circuit Breaker

```typescript
// Prevent cascading failures
class CircuitBreaker {
  private state: "CLOSED" | "OPEN" | "HALF_OPEN" = "CLOSED";
  private failureCount = 0;
  private lastFailureTime = 0;
  private readonly threshold = 5;
  private readonly timeout = 60000; // 1 minute

  async execute<T>(fn: () => Promise<T>): Promise<T> {
    if (this.state === "OPEN") {
      if (Date.now() - this.lastFailureTime > this.timeout) {
        this.state = "HALF_OPEN";
      } else {
        throw new Error("Circuit breaker is OPEN");
      }
    }

    try {
      const result = await fn();
      this.onSuccess();
      return result;
    } catch (error) {
      this.onFailure();
      throw error;
    }
  }

  private onSuccess() {
    this.failureCount = 0;
    this.state = "CLOSED";
  }

  private onFailure() {
    this.failureCount++;
    this.lastFailureTime = Date.now();
    if (this.failureCount >= this.threshold) {
      this.state = "OPEN";
    }
  }
}

// Usage
const breaker = new CircuitBreaker();
const result = await breaker.execute(() => externalAPI.call());
```

### 3. Timeout Handling

```typescript
// Prevent hanging requests
function withTimeout<T>(
  promise: Promise<T>,
  timeoutMs: number
): Promise<T> {
  return Promise.race([
    promise,
    new Promise<T>((_, reject) =>
      setTimeout(() => reject(new Error("Timeout")), timeoutMs)
    ),
  ]);
}

// Usage
const result = await withTimeout(
  aiService.generateResponse(message),
  5000 // 5 second timeout
);
```

### 4. Graceful Degradation

```typescript
// Fallback when service is unavailable
async function getContactWithFallback(contactId: string) {
  try {
    // Try primary service
    return await contactService.getContact(contactId);
  } catch (error) {
    logger.warn("Primary service failed, using cache", { contactId });

    // Fallback to cache
    const cached = await redis.get(`contact:${contactId}`);
    if (cached) return JSON.parse(cached);

    // Last resort: return minimal data
    return { id: contactId, name: "Unknown" };
  }
}
```

